let result = {};
let isFallback = false;
let errDetails = '';

if ($json.error || !$json.candidates || !$json.candidates[0] || !$json.candidates[0].content || !$json.candidates[0].content.parts || !$json.candidates[0].content.parts[0]) {
  isFallback = true;
  errDetails = 'Gemini API Error or invalid response structure: ' + JSON.stringify($json);
} else {
  let text = $json.candidates[0].content.parts[0].text.trim();
  let cleanJson = text.replace(/```json/g, '').replace(/```/g, '').trim();

  try {
    result = JSON.parse(cleanJson);

    if (result.resposta_cliente === undefined || result.resposta_cliente === null || String(result.resposta_cliente).trim() === '') {
      isFallback = true;
      errDetails = 'Parsed JSON is missing resposta_cliente: ' + cleanJson;
    }
  } catch (e) {
    isFallback = true;
    errDetails = 'JSON Parse Error: ' + e.message + ' | Raw text: ' + text;
  }
}

if (isFallback) {
  let userMsg = '';
  try {
    userMsg = ($node["Entrada Aninha Atendimento"].json.body.mensagem_atual || '').toLowerCase();
  } catch (e) {
    userMsg = '';
  }

  const residentialKeywords = [
    "apartamento", "apto", "minha casa", "residência", "residencial", 
    "chuveiro", "tomada", "disjuntor do meu apartamento", "casa"
  ];
  let isResidential = false;
  for (const keyword of residentialKeywords) {
    if (userMsg.includes(keyword)) {
      isResidential = true;
      break;
    }
  }

  if (isResidential) {
    result = {
      "responder_cliente": true,
      "resposta_cliente": "No momento, a DL Soluções Condominiais atende demandas técnicas voltadas a condomínios, escolas, empresas e suporte a equipamentos profissionais. Para esse tipo de solicitação residencial avulsa, não conseguimos seguir com atendimento.",
      "intencao_atual": "residencial_bloqueado",
      "etapa_funil": "bloqueado_residencial",
      "segmento": "residencial",
      "dados_coletados": {},
      "lead_qualificado": false,
      "encaminhar_humano": false,
      "motivo_encaminhamento": null,
      "bloquear": true,
      "motivo_bloqueio": "atendimento residencial avulsa",
      "is_fallback": true,
      "error_details": errDetails
    };
  } else {
    result = {
      "responder_cliente": true,
      "resposta_cliente": "Recebi sua mensagem. Para seguir com a Avaliação Técnica, me informe o nome do condomínio, bairro e o problema principal identificado.",
      "intencao_atual": "indefinido",
      "etapa_funil": "coletando_dados_condominio",
      "segmento": "indefinido",
      "dados_coletados": {},
      "lead_qualificado": false,
      "encaminhar_humano": false,
      "motivo_encaminhamento": null,
      "bloquear": false,
      "motivo_bloqueio": null,
      "is_fallback": true,
      "error_details": errDetails
    };
  }
}

return [{ json: result }];

